INSERT INTO `intangible_cultural_heritage` VALUES (1,'青田米塑技艺','传统技艺','面塑','清代','浙江省丽水市青田县','municipal','以糯米为原料，塑造花鸟、人物等造型，用于节庆祭祀，工艺精巧','清代起源于青田民间，最初用于祭祀供品，后发展为民间工艺品','县级非遗瑰宝，承载青田民间民俗文化，手工技艺传承价值突出','陈月英','[\"qingtianmisu1.jpg\", \"qingtianmisu2.jpg\"]','https://example.com/qingtianmisu.mp4','[\"米塑玲珑藏童趣，巧手匠心绘丰年\"]','[\"元宵\", \"清明\"]',28.457500,120.393000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(2,'安吉竹编技艺','传统技艺','竹编','明代','浙江省湖州市安吉县','municipal','以当地毛竹为原料，编织生活器具与工艺品，纹理清晰、坚固耐用','明代传入安吉，依托当地竹资源发展，民间广泛传承','体现安吉竹文化特色，实用与艺术结合，县级非遗重要载体','李根才','[\"anjizhubian1.jpg\"]','https://example.com/anjizhubian.mp4','[\"翠竹编成千般艺，安吉竹韵传千年\"]','[\"小满\", \"芒种\"]',30.688000,119.689000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(3,'歙县竹雕技艺','传统技艺','雕刻技艺','清代','安徽省黄山市歙县','municipal','以竹为原料，雕刻山水、人物、花鸟，工艺细腻，兼具观赏性','清代兴起于歙县，受徽派雕刻影响，传承至今','徽派工艺延伸，县级非遗珍品，展现民间雕刻匠心','王建国','[\"shexianzhudiao1.jpg\"]','https://example.com/shexianzhudiao.mp4','[\"竹刻玲珑藏雅韵，一刀一刻见初心\"]','[\"寒露\", \"霜降\"]',29.874700,118.441000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(4,'浦江剪纸技艺','传统美术','剪纸','明代','浙江省金华市浦江县','municipal','以红纸为原料，剪刻花鸟、人物、民俗场景，线条流畅，风格质朴','明代起源于浦江民间，节庆期间广泛使用，传承至今','县级民间美术瑰宝，承载浦江民俗文化，群众基础深厚','张桂英','[\"pujiangjianzhi1.jpg\"]','https://example.com/pujiangjianzhi.mp4','[\"一纸一剪生万象，浦江剪纸韵悠长\"]','[\"春节\", \"元宵\"]',29.498000,119.886000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(5,'新绛木版年画技艺','传统美术','年画','清代','山西省运城市新绛县','municipal','以木版雕刻、套色印刷，题材以民俗吉祥为主，风格古朴','清代传入新绛，民间艺人代代传承，是当地节庆重要装饰','县级民俗美术珍品，保留传统年画技艺，具有浓郁地方特色','李福明','[\"xinjiangnianhua1.jpg\"]','https://example.com/xinjiangnianhua.mp4','[\"木版年画传晋韵，古朴吉祥庆太平\"]','[\"春节\", \"立春\"]',35.638000,111.264000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(6,'丰都泥塑技艺','传统美术','泥塑','清代','重庆市丰都县','municipal','以当地黄泥土为原料，塑造民俗人物、神像，造型生动，寓意吉祥','清代起源于丰都民间，与当地鬼城文化结合，传承至今','承载丰都地方文化，县级非遗瑰宝，手工艺术价值突出','刘世全','[\"fengdunisun1.jpg\"]','https://example.com/fengdunisun.mp4','[\"泥塑传神藏古韵，丰都文化代代传\"]','[\"清明\", \"谷雨\"]',29.863500,107.735000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(7,'婺源晒秋习俗','民俗','民间习俗','明代','江西省上饶市婺源县','municipal','秋季丰收后，将农作物晾晒于房前屋后，形成独特景观，寓意丰收吉祥','明代起源于婺源徽州村落，依托山地地形形成，传承至今','县级民俗瑰宝，展现徽州农耕文化，兼具观赏性与文化价值','全民传承','[\"wuyuanShaiqiu1.jpg\"]','https://example.com/wuyuanShaiqiu.mp4','[\"晒秋满院皆金黄，徽州古韵醉心房\"]','[\"立秋\", \"处暑\"]',29.294400,117.831000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(8,'商南花灯习俗','民俗','民间表演','清代','陕西省商洛市商南县','municipal','春节期间，村民制作花灯、舞花灯，祈求平安丰收，场面热闹','清代兴起于商南民间，融合当地民间音乐与舞蹈，传承至今','县级民俗载体，展现陕南民间风情，增强村民凝聚力','全民传承','[\"shangnanhuadeng1.jpg\"]','https://example.com/shangnanhuadeng.mp4','[\"花灯璀璨迎新春，陕南风情醉人心\"]','[\"春节\", \"元宵\"]',33.586000,110.824000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(9,'连城游大龙习俗','民俗','民间盛会','明代','福建省龙岩市连城县','municipal','元宵节期间，村民制作大龙，巡游村落，祈求风调雨顺、国泰民安','明代起源于连城，龙身长达数十米，参与人数众多，传承至今','县级民俗瑰宝，展现客家文化特色，具有浓厚的民间氛围','全民传承','[\"lianchenglong1.jpg\"]','https://example.com/lianchenglong.mp4','[\"大龙巡游迎元宵，客家风情耀连城\"]','[\"元宵\", \"雨水\"]',25.728000,116.737000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(10,'通海洞经音乐','传统音乐','丝竹乐','清代','云南省玉溪市通海县','municipal','以丝竹乐器演奏，曲调典雅悠扬，源于道教音乐，流传于民间','清代传入通海，融合当地民间音乐，用于祭祀、庆典等活动','县级传统音乐瑰宝，保留道教音乐特色，具有较高的艺术价值','张正明','[\"tonghaidongjing1.jpg\"]','https://example.com/tonghaidongjing.mp4','[\"洞经丝竹传古韵，通海清音润心田\"]','[\"秋分\", \"霜降\"]',24.058000,102.783000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(11,'宜黄采茶戏','传统戏剧','采茶戏','清代','江西省抚州市宜黄县','municipal','流行于宜黄民间，以采茶题材为主，唱腔淳朴，表演生动','清代起源于宜黄农村，融合民间歌舞，贴近生活，传承至今','县级传统戏剧瑰宝，展现农村生活风貌，群众基础深厚','黄玉英','[\"yihuangcaicha1.jpg\"]','https://example.com/yihuangcaicha.mp4','[\"采茶小调唱田园，宜黄古韵传千年\"]','[\"清明\", \"谷雨\"]',27.537000,116.211000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),(12,'岷县中药切片技艺','传统医药','制药技艺','清代','甘肃省定西市岷县','municipal','以岷县当地中药材为原料，采用传统手法切片，保证药效，工艺精湛','清代兴起于岷县，依托当地中药材资源，传承至今','县级传统医药瑰宝，保障中药材药效，助力地方医药发展','赵文举','[\"minxianqiepian1.jpg\"]','https://example.com/minxianqiepian.mp4','[\"药片切就藏妙术，岷县药香传四方\"]','[\"清明\", \"谷雨\"]',34.408000,104.074000,0,0,'2026-03-26 10:03:49','2026-03-26 10:03:49'),