INSERT INTO `travel_posts` VALUES (1,10011,'游戏美景治愈人心','漂浮在寂静无垠的大海上','travel','[\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/1/3264b64d-d59b-4620-8689-2e35dbd01152.png\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/1/c159c89f-a9fd-4651-9abd-0ec45e032aa4.png\"]','[\"风景\",\"游戏\",\"vibe\"]',1,73,5,'2026-03-19 13:51:19','2026-03-24 18:42:08',NULL,1,'zh'),(2,10000,'黄鹤楼不只是与火车同框｜与汽车同框也出片','黄鹤楼与京广线火车同框是一网红机位（透过铁丝网拍摄），外地人来黄鹤楼游玩打卡，通常会在此机位拍摄一两张黄鹤楼与火车同框照。但很少人知道，在此机位的马路正对面人行道上，也有一个拍摄黄鹤楼的绝佳机位：可以拍到黄鹤楼与过往长江大桥的汽车同框照。\n机位点：\n与网红铁丝网打卡点马路相隔，即大桥南侧人行道上；\n到达路线：\n①司门口天桥横穿铁路、公路，上南侧人行道，往桥头堡方向步行五六百米即到；\n②中华路码头沿江逆行，穿过大桥后立即左拐，沿台阶拾级而上，到达公路桥面即是。','travel','[\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/2/85d1f028-6071-4825-92a0-4e92322710df.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/2/c1c45dd4-d65b-44d5-b1ae-d49d20792514.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/2/e7160a3b-94da-47dd-82f5-eae2ca242c76.jpg\"]','[\"旅行\",\"风景\",\"攻略\"]',1,86,3,'2026-03-19 14:36:54','2026-03-24 18:43:18',NULL,1,'zh'),(3,10000,'有被这几晚的东湖美到！','下午6点多，在东湖边的慢跑~','travel','[\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/3/3eaa5725-3a4d-42bd-a57d-daf6e2deb1ca.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/3/863ace20-e1a5-4eb6-8417-563837e8757e.jpg\"]','[\"武汉\",\"东湖\",\"大自然\",\"风景\",\"晚霞\"]',1,23,1,'2026-03-19 16:05:31','2026-03-25 09:39:46',NULL,1,'zh'),(4,10011,'武汉被严重低估的山寺樱花！好有禅意','宝通寺樱花 宝通寺对面梦时代的粉色樱花开的真好，有十几颗，楼上可以拍宝通寺全景','tips','[\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/4/c8307dfe-800f-4c4a-8cb5-50ff389a4ff0.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/4/67e5ea6c-165b-4ec4-a143-3c865bb2fce4.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/4/418b65c4-2945-4986-9bb9-b26cf9e6efc1.jpg\"]','[\"风景\",\"宝通寺\",\"樱花\",\"春天\"]',1,17,0,'2026-03-20 09:20:15','2026-03-25 09:40:02',NULL,2,'zh'),(5,10000,'A one-day tour of the Forbidden City','Today I started my Beijing trip and my first stop was the Forbidden City. Take a look at the photos I took.','travel','[\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/5/eb8873f9-2140-4958-985a-7de9ca7565c8.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/5/7d8f8992-da48-4b95-956a-e8db25bc0aa5.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/5/392f3f84-ef3c-4e70-8256-6b62f75a2fd3.jpg\"]','[\"Travel\",\"ForbiddenCity\",\"Beijing\"]',1,15,0,'2026-03-20 17:53:41','2026-03-24 18:39:09',NULL,0,'auto'),(6,10011,'111','interesting\nfunny','travel','[\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/6/67129ed2-ae7d-48c1-bbef-2c48ded959ed.jpg\"]','[\"风景\"]',1,31,3,'2026-03-21 00:17:37','2026-03-24 18:44:57',NULL,2,'en'),(7,10020,'别只拍金光穿洞了，来拍佛香阁亮灯吧！','今天给大家分享的是佛香阁亮灯。\n一年一度金光穿洞又开始，不过人依旧多得给力，实在挤不进去的话建议还是从西门进，来畅观堂附近拍颐和园亮灯。尤其这个机位，佛香阁和豳风桥都亮起来后，等到蓝调时刻，会非常有意境，推荐大家都来打卡。佛香阁周五周六亮灯。','travel','[\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/7/5ea1bc27-60d3-452a-b5ba-dd0e2c5235e9.jpg\",\"https://travelate.oss-cn-wuhan-lr.aliyuncs.com/posts/7/fa523867-578a-4892-9cb4-59e020ca2a70.jpg\"]','[\"北京旅游\",\"古建筑摄影\",\"颐和园\",\"摄影\"]',1,6,1,'2026-03-21 03:23:40','2026-03-25 09:39:29',NULL,0,'zh');
/*!40000 ALTER TABLE `travel_posts` ENABLE KEYS */;
UNLOCK TABLES;

